import Blockly from 'blockly/core';

// block type naming rule : {toolbox_name}_{block_description}

const headsetAngleJson = {
	"message0": "angle of headset",
	"output": "Number",
	"style": "perception_blocks"
}

Blockly.Blocks['c_perception_headsetAngle'] = {
	init: function() {
		this.jsonInit(headsetAngleJson);
	}
}

const hipAngleJson = {
	"message0": "angle of %1 hip",
	"args0": [
		{
			'type': 'field_dropdown',
			'name': 'DIRECTION',
			'options': [			
				['LEFT', 'left'],
				['RIGHT', 'right']
			],
		},
	],
	"output": "Number",
	"style": "perception_blocks"
}

Blockly.Blocks['c_perception_hipAngle'] = {
	init: function() {
		this.jsonInit(hipAngleJson);
	}
}

const wheelSpeedJson = {
	"message0": "speed of %1 wheel",
	"args0": [
		{
			'type': 'field_dropdown',
			'name': 'DIRECTION',
			'options': [			
				['LEFT', 'left'],
				['RIGHT', 'right']
			],
		},
	],
	"output": "Number",
	"style": "perception_blocks"
}

Blockly.Blocks['c_perception_wheelSpeed'] = {
	init: function() {
		this.jsonInit(wheelSpeedJson);
	}
}

