	}
}

const startCameraJson = {
	"message0": "start RGB camera",
	"inputsInline": false,
	"previousStatement": null,
	"nextStatement": null,
	"style": "perception_blocks",
}

Blockly.Blocks['c_perception_startCamera'] = {
	init: function() {
		this.jsonInit(startCameraJson);
	}
}

const stopCameraJson = {
	"message0": "stop RGB camera",
	"inputsInline": false,
	"previousStatement": null,
	"nextStatement": null,
	"style": "perception_blocks",
}

Blockly.Blocks['c_perception_stopCamera'] = {
	init: function() {
		this.jsonInit(stopCameraJson);
	}
}

const personDetectionJson = {
	"message0": "person detected",
	"output": "Boolean",
	"style": "perception_blocks"
}

Blockly.Blocks['c_perception_personDetection'] = {
	init: function() {
		this.jsonInit(personDetectionJson);
	}
}

const fallDownDetectionJson = {
	"message0": "fall down detected",
	"output": "Boolean",
	"style": "perception_blocks"
}

Blockly.Blocks['c_perception_fallDownDetection'] = {
